// Package deviceflow is an RFC 8628 OAuth 2.0 Device Authorization
// Grant client.
//
// Construct a Client with the issuer's BaseURL plus the paths and
// client_id it expects, then call StartDeviceAuth followed by repeated
// PollDeviceAuth calls until either a TokenSet comes back or a
// terminal error is returned. Caller drives the polling loop and
// adjusts the interval on ErrSlowDown per RFC 8628 §3.5.
//
// The client is provider-agnostic: every server-specific value
// (endpoint paths, client_id, optional scope) is configured at
// construction time. There is no provider detection.
package deviceflow

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/entireio/auth-go/internal/oauthhttp"
	"github.com/entireio/auth-go/tokens"
)

// nowFunc is the package's clock. Tests override it; production uses
// time.Now.
var nowFunc = time.Now

// deviceCodeGrantType is the RFC 8628 token-endpoint grant_type for
// polling device-flow authorization.
const deviceCodeGrantType = "urn:ietf:params:oauth:grant-type:device_code"

// DeviceCode is the response from the device authorization endpoint
// (RFC 8628 §3.2). Pass DeviceCode through to subsequent PollDeviceAuth
// calls and show UserCode + VerificationURI to the user.
type DeviceCode struct {
	DeviceCode              string `json:"device_code"`
	UserCode                string `json:"user_code"`
	VerificationURI         string `json:"verification_uri"`
	VerificationURIComplete string `json:"verification_uri_complete"`
	ExpiresIn               int    `json:"expires_in"`
	Interval                int    `json:"interval"`
}

// DefaultRequestTimeout caps a single device-flow HTTP round-trip
// (StartDeviceAuth or one PollDeviceAuth call). Set conservatively:
// healthy device-flow endpoints respond in sub-seconds, so the cap
// mainly defends against slow-loris responses dripping bytes within
// MaxResponseBytes — see Client.RequestTimeout for the per-Client
// override. The polling-loop interval is the caller's concern; this
// timeout governs only the individual HTTP request.
const DefaultRequestTimeout = 30 * time.Second

// Client polls an RFC 8628 device authorization grant.
//
// All configuration is explicit; the package has no global state and
// no implicit URLs. Provide BaseURL, ClientID, and the two endpoint
// paths; the rest is RFC 8628 mechanics.
type Client struct {
	// Transport supplies the http.RoundTripper used for all calls.
	// nil → http.DefaultTransport. The library builds its own
	// *http.Client around this transport so callers can't trivially
	// pass a *http.Client with a misconfigured TLS bypass (the prior
	// HTTP *http.Client field made that a one-liner). Custom
	// RoundTrippers that wrap or replace TLS verification remain the
	// caller's responsibility; this hook is for observability
	// (request/response logging) and per-environment proxies, not
	// security bypass.
	Transport http.RoundTripper

	BaseURL        string
	ClientID       string
	Scope          string
	UserAgent      string
	DeviceCodePath string
	TokenPath      string

	// RequestTimeout is the per-request deadline applied via
	// context.WithTimeout on top of the caller's context. Zero falls
	// back to DefaultRequestTimeout. Negative disables the cap (useful
	// for tests that want to drive timing via the caller's ctx alone).
	RequestTimeout time.Duration

	// AllowInsecureHTTP permits http:// BaseURLs. Default (false) is
	// reject — the device-flow token endpoint returns the user's
	// freshly-minted access token in the response body and must be
	// TLS-protected end to end. Production callers MUST leave this
	// false; only tests and local development pinned to loopback
	// should flip it.
	AllowInsecureHTTP bool
}

// httpClient builds the *http.Client used for one request. See
// oauthhttp.HTTPClient for the construction policy (fresh per call,
// shared underlying Transport, no Client.Timeout).
func (c *Client) httpClient() *http.Client {
	return oauthhttp.HTTPClient(c.Transport)
}

// requestTimeout resolves the effective per-request timeout: the
// configured RequestTimeout if positive, the package default if zero,
// or zero (no cap) if negative.
func (c *Client) requestTimeout() time.Duration {
	switch {
	case c.RequestTimeout < 0:
		return 0
	case c.RequestTimeout == 0:
		return DefaultRequestTimeout
	default:
		return c.RequestTimeout
	}
}

// Sentinel errors returned by PollDeviceAuth when the token endpoint
// responds with a recognised RFC 8628 §3.5 error code. Callers branch
// on these with errors.Is and adjust their polling loop accordingly.
var (
	// ErrAuthorizationPending — user has not yet approved or denied.
	// Caller polls again at the existing interval.
	ErrAuthorizationPending = errors.New("authorization_pending")

	// ErrSlowDown — caller is polling too fast. Caller bumps the
	// interval (per RFC 8628 §3.5, by at least 5 seconds) and tries
	// again.
	ErrSlowDown = errors.New("slow_down")

	// ErrAccessDenied — user denied the request. Terminal.
	ErrAccessDenied = errors.New("access_denied")

	// ErrExpiredToken — device code expired before the user approved.
	// Terminal; restart with a fresh StartDeviceAuth.
	ErrExpiredToken = errors.New("expired_token")

	// ErrInvalidGrant — device code already redeemed, malformed, or
	// otherwise rejected. Terminal.
	ErrInvalidGrant = errors.New("invalid_grant")
)

// errCodeToSentinel maps an RFC 8628 §3.5 error code string to the
// matching sentinel. Unknown codes fall through to a generic error.
func errCodeToSentinel(code string) error {
	switch code {
	case "authorization_pending":
		return ErrAuthorizationPending
	case "slow_down":
		return ErrSlowDown
	case "access_denied":
		return ErrAccessDenied
	case "expired_token":
		return ErrExpiredToken
	case "invalid_grant":
		return ErrInvalidGrant
	default:
		return fmt.Errorf("oauth error: %s", code)
	}
}

// StartDeviceAuth requests a fresh device code from the authorization
// server. The returned DeviceCode is opaque to the client; pass it
// back unmodified on every PollDeviceAuth.
func (c *Client) StartDeviceAuth(ctx context.Context) (*DeviceCode, error) {
	if timeout := c.requestTimeout(); timeout > 0 {
		var cancel context.CancelFunc
		ctx, cancel = context.WithTimeout(ctx, timeout)
		defer cancel()
	}

	body := url.Values{}
	body.Set("client_id", c.ClientID)
	if c.Scope != "" {
		body.Set("scope", c.Scope)
	}

	resp, err := c.postForm(ctx, c.DeviceCodePath, body)
	if err != nil {
		return nil, fmt.Errorf("start device auth: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, readAPIError(resp, "start device auth")
	}

	var result DeviceCode
	if err := oauthhttp.ReadAndDecodeJSON(resp.Body, &result, true); err != nil {
		return nil, fmt.Errorf("start device auth: %w", err)
	}
	if err := validateVerificationURI(result.VerificationURI, c.AllowInsecureHTTP); err != nil {
		return nil, fmt.Errorf("start device auth: verification_uri: %w", err)
	}
	if result.VerificationURIComplete != "" {
		if err := validateVerificationURI(result.VerificationURIComplete, c.AllowInsecureHTTP); err != nil {
			return nil, fmt.Errorf("start device auth: verification_uri_complete: %w", err)
		}
	}
	return &result, nil
}

// ErrUnsafeVerificationURI is returned when the authorization server
// returns a verification_uri that fails minimum-trust checks. Defense
// against a compromised or misconfigured AS pointing users at a
// phishing page: the URL we'd otherwise echo to the user and open in
// their browser carries the user code, so a wrong destination is a
// direct credential-harvesting vector.
var ErrUnsafeVerificationURI = errors.New("unsafe verification_uri")

// validateVerificationURI rejects URIs that obviously look like
// phishing or shell-injection attempts:
//
//   - Must parse as an absolute URL.
//   - Scheme must be https (or http only when allowInsecureHTTP is
//     set AND the host is loopback — production never qualifies).
//   - Must not embed userinfo (user:password@host tricks the eye).
//   - Must not contain control characters (CR/LF/etc.) that could
//     break terminal output or sneak past glance-checks.
//
// This is the bottom-floor check; the embedding CLI is still expected
// to show the URL to the user for visual inspection, and the user is
// expected to read it before opening.
func validateVerificationURI(raw string, allowInsecureHTTP bool) error {
	if raw == "" {
		return fmt.Errorf("%w: missing", ErrUnsafeVerificationURI)
	}
	for _, r := range raw {
		if r < 0x20 || r == 0x7f {
			return fmt.Errorf("%w: contains control character", ErrUnsafeVerificationURI)
		}
	}
	u, err := url.Parse(raw)
	if err != nil {
		return fmt.Errorf("%w: parse: %w", ErrUnsafeVerificationURI, err)
	}
	if u.Host == "" {
		return fmt.Errorf("%w: missing host", ErrUnsafeVerificationURI)
	}
	if u.User != nil {
		return fmt.Errorf("%w: embedded userinfo not permitted", ErrUnsafeVerificationURI)
	}
	switch u.Scheme {
	case "https":
		// fine
	case "http":
		if !allowInsecureHTTP {
			return fmt.Errorf("%w: scheme must be https", ErrUnsafeVerificationURI)
		}
		host := u.Hostname()
		if host != "localhost" && host != "127.0.0.1" && host != "::1" {
			return fmt.Errorf("%w: http only permitted on loopback hosts", ErrUnsafeVerificationURI)
		}
	default:
		return fmt.Errorf("%w: scheme %q (must be https)", ErrUnsafeVerificationURI, u.Scheme)
	}
	return nil
}

// PollDeviceAuth exchanges deviceCode for a TokenSet at the token
// endpoint.
//
// On success, returns a TokenSet with absolute expiry derived from
// the server's expires_in. On any RFC 8628 §3.5 error code, returns
// the matching sentinel error from this package. Other failures
// (network, malformed responses) are wrapped with context.
//
// Most callers want PollUntil instead — it drives the poll loop,
// honours the interval, applies the RFC 8628 §3.5 +5s slow_down bump,
// and stops at the device-code's ExpiresIn ceiling. Use PollDeviceAuth
// directly only when you need to render the per-tick state yourself
// (e.g. animating a TUI spinner).
func (c *Client) PollDeviceAuth(ctx context.Context, deviceCode string) (*tokens.TokenSet, error) {
	if timeout := c.requestTimeout(); timeout > 0 {
		var cancel context.CancelFunc
		ctx, cancel = context.WithTimeout(ctx, timeout)
		defer cancel()
	}

	body := url.Values{}
	body.Set("grant_type", deviceCodeGrantType)
	body.Set("client_id", c.ClientID)
	body.Set("device_code", deviceCode)

	resp, err := c.postForm(ctx, c.TokenPath, body)
	if err != nil {
		return nil, fmt.Errorf("poll device auth: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, readAPIError(resp, "poll device auth")
	}

	var raw struct {
		AccessToken  string `json:"access_token"`
		TokenType    string `json:"token_type"`
		ExpiresIn    int    `json:"expires_in"`
		RefreshToken string `json:"refresh_token"`
		Scope        string `json:"scope"`
	}
	if err := oauthhttp.ReadAndDecodeJSON(resp.Body, &raw, false); err != nil {
		return nil, fmt.Errorf("poll device auth: %w", err)
	}

	if raw.AccessToken == "" {
		return nil, errors.New("poll device auth: server returned 200 with no access token")
	}

	t := &tokens.TokenSet{
		AccessToken:  raw.AccessToken,
		RefreshToken: raw.RefreshToken,
		TokenType:    raw.TokenType,
		Scope:        raw.Scope,
	}
	if raw.ExpiresIn > 0 {
		t.ExpiresAt = nowFunc().Add(time.Duration(raw.ExpiresIn) * time.Second)
	}
	return t, nil
}

// postForm POSTs body as application/x-www-form-urlencoded to a path
// resolved against the client's BaseURL. The caller is responsible
// for applying any per-request timeout via context.WithTimeout — the
// timeout must cover the body-read that happens after postForm
// returns, so cancel-on-return here would interrupt that read.
func (c *Client) postForm(ctx context.Context, path string, body url.Values) (*http.Response, error) {
	endpoint, err := resolveURL(c.BaseURL, path, c.AllowInsecureHTTP)
	if err != nil {
		return nil, fmt.Errorf("resolve URL %s: %w", path, err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, strings.NewReader(body.Encode()))
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}

	req.Header.Set("Accept", "application/json")
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
	if c.UserAgent != "" {
		req.Header.Set("User-Agent", c.UserAgent)
	}

	resp, err := c.httpClient().Do(req)
	if err != nil {
		return nil, fmt.Errorf("request %s: %w", path, err)
	}
	return resp, nil
}

// ErrInsecureBaseURL is returned when device-flow requests are made
// against an http:// BaseURL without AllowInsecureHTTP set. The token
// endpoint returns the user's access token in the response body — over
// plain HTTP that's a credential in the clear. Re-exported from
// internal/oauthhttp so callers can errors.Is(err, deviceflow.ErrInsecureBaseURL)
// regardless of which package raised it.
var ErrInsecureBaseURL = oauthhttp.ErrInsecureBaseURL

// ErrAbsolutePath is returned when DeviceCodePath or TokenPath is an
// absolute or scheme-relative URL rather than a path relative to
// BaseURL. Go's url.ResolveReference *replaces* the base when handed
// an absolute reference, so accepting an absolute path would let any
// caller who can influence the configuration (env var, config file,
// server-discovery doc) redirect the device-code or token request to
// an attacker — and in the token-endpoint case, capture the user's
// access token. Re-exported from internal/oauthhttp.
var ErrAbsolutePath = oauthhttp.ErrAbsolutePath

func resolveURL(baseURL, path string, allowInsecureHTTP bool) (string, error) {
	return oauthhttp.ResolveURL(baseURL, path, allowInsecureHTTP) //nolint:wrapcheck // pass through with sentinel-preserving semantics
}

type errorResponse struct {
	Error            string `json:"error"`
	ErrorDescription string `json:"error_description"`
}

func readAPIErrorResponse(resp *http.Response) (*errorResponse, error) {
	body, err := io.ReadAll(io.LimitReader(resp.Body, oauthhttp.MaxResponseBytes))
	if err != nil {
		return nil, fmt.Errorf("status %d", resp.StatusCode)
	}

	var apiErr errorResponse
	if err := json.Unmarshal(body, &apiErr); err == nil && strings.TrimSpace(apiErr.Error) != "" {
		return &apiErr, nil
	}

	text := strings.TrimSpace(string(body))
	if text != "" {
		return nil, fmt.Errorf("status %d: %s", resp.StatusCode, text)
	}
	return nil, fmt.Errorf("status %d", resp.StatusCode)
}

// readAPIError surfaces an error-shaped response. It routes the AS's
// `error` code through errCodeToSentinel so callers can errors.Is
// regardless of which endpoint produced the failure, and appends a
// sanitised error_description when one was supplied — capping length
// and stripping control characters that would otherwise let a hostile
// AS write ANSI escapes / overflow into the user's terminal.
func readAPIError(resp *http.Response, action string) error {
	apiErr, parseErr := readAPIErrorResponse(resp)
	if parseErr != nil {
		return fmt.Errorf("%s: %w", action, parseErr)
	}
	err := errCodeToSentinel(apiErr.Error)
	if desc := sanitizeDescription(apiErr.ErrorDescription); desc != "" {
		return fmt.Errorf("%s: %w: %s", action, err, desc)
	}
	return fmt.Errorf("%s: %w", action, err)
}

// sanitizeDescription is a thin alias kept for in-package readability.
// The implementation lives in internal/oauthhttp.
func sanitizeDescription(s string) string { return oauthhttp.SanitizeDescription(s) }

// slowDownBump is the per-RFC 8628 §3.5 mandated interval increase
// applied each time the AS responds with `slow_down`. RFC says "at
// least 5 seconds"; we go with exactly 5. Declared as a var rather
// than const so PollUntil tests can shrink it without burning real
// wall-clock seconds. Production callers should never mutate this.
var slowDownBump = 5 * time.Second

// pollInterval picks the effective poll interval for a device-code
// response.
//
//   - RFC 8628 §3.5 lets the AS omit `interval`, in which case the
//     client SHOULD use 5 seconds.
//   - Non-positive values (omitted, zero, negative) fall back to
//     defaultInterval — a literal `"interval":0` would otherwise hot-
//     loop against the token endpoint.
//   - Values past maxIntervalSeconds are clamped to 1h. Without a
//     ceiling, a hostile or buggy AS could effectively park the poll
//     loop until ExpiresIn fires; on 64-bit platforms an extreme
//     value could also overflow time.Duration's nanosecond range
//     (max ~292y). 1h is several orders of magnitude above any real
//     device-flow interval and still safely bounded.
func pollInterval(dc *DeviceCode) time.Duration {
	const defaultInterval = 5 * time.Second
	const maxIntervalSeconds = 3600
	switch {
	case dc.Interval <= 0:
		return defaultInterval
	case dc.Interval > maxIntervalSeconds:
		return time.Duration(maxIntervalSeconds) * time.Second
	default:
		return time.Duration(dc.Interval) * time.Second
	}
}

// PollUntil drives the device-flow poll loop end-to-end. Most embedders
// want this helper rather than calling PollDeviceAuth manually — it
// owns the loop discipline that RFC 8628 §5.5 calls out as the
// difference between a polite client and a DoS source.
//
// Behaviour:
//
//   - Waits dc.Interval (defaulting to 5s, clamped to 1s minimum)
//     between successive poll calls.
//   - On ErrSlowDown, bumps the interval by 5s permanently per RFC
//     8628 §3.5. Subsequent slow_down responses bump again.
//   - Stops with the most-recent error when dc.ExpiresIn elapses since
//     PollUntil was called. If the AS omitted expires_in (zero or
//     negative), falls back to defaultExpiresIn so the loop is always
//     bounded — closes a hostile-AS DoS vector parallel to the
//     pollInterval clamp.
//   - Returns the TokenSet on success.
//   - Returns ctx.Err() (wrapped) when the caller cancels.
//   - Returns terminal sentinels (ErrAccessDenied, ErrExpiredToken,
//     ErrInvalidGrant) unwrapped, plus any unknown OAuth error verbatim,
//     so callers can errors.Is.
func (c *Client) PollUntil(ctx context.Context, dc *DeviceCode) (*tokens.TokenSet, error) {
	if dc == nil {
		return nil, errors.New("PollUntil: DeviceCode is nil")
	}
	if dc.DeviceCode == "" {
		return nil, errors.New("PollUntil: DeviceCode.DeviceCode is empty")
	}

	interval := pollInterval(dc)
	expiresInSecs, defaulted := pollExpiresIn(dc)
	deadline := nowFunc().Add(time.Duration(expiresInSecs) * time.Second)

	for {
		ts, err := c.PollDeviceAuth(ctx, dc.DeviceCode)
		switch {
		case err == nil:
			return ts, nil
		case errors.Is(err, ErrAuthorizationPending):
			// keep polling
		case errors.Is(err, ErrSlowDown):
			interval += slowDownBump
		default:
			// All other errors (terminal sentinels, unknown OAuth
			// codes, network/decode failures) are propagated. The
			// caller decides whether to retry.
			return nil, err
		}

		if !nowFunc().Before(deadline) {
			if defaulted {
				return nil, fmt.Errorf("PollUntil: default expiry (%ds) reached; AS omitted expires_in", expiresInSecs)
			}
			return nil, fmt.Errorf("PollUntil: device code expired after %ds", expiresInSecs)
		}

		select {
		case <-ctx.Done():
			return nil, fmt.Errorf("PollUntil: %w", ctx.Err())
		case <-time.After(interval):
		}
	}
}

// defaultPollExpiresIn caps PollUntil when the AS omits expires_in.
// 30 minutes mirrors what most production device-flow servers issue
// (RFC 8628 doesn't mandate a value); long enough that legitimate
// users have time to authenticate, short enough that a buggy server
// can't keep us polling indefinitely. Declared as a var so the
// PollUntil tests can shrink it without burning real wall-clock
// minutes; production code must not mutate it.
var defaultPollExpiresIn = 30 * 60

// pollExpiresIn returns the effective expires_in (in seconds) for a
// device-code response, plus whether the value came from the default
// fallback (true) or the wire value (false). RFC 8628 expects the AS
// to provide expires_in, but a buggy or hostile server might omit
// it — in which case we must still bound the loop.
func pollExpiresIn(dc *DeviceCode) (secs int, defaulted bool) {
	if dc.ExpiresIn <= 0 {
		return defaultPollExpiresIn, true
	}
	return dc.ExpiresIn, false
}

// Package sts is an RFC 8693 OAuth 2.0 Token Exchange client.
//
// Construct a Client with the issuer's BaseURL and the token endpoint
// path, then call Exchange with a populated ExchangeRequest. The
// package is provider-agnostic: every server-specific value (endpoint
// path, requested-token-type URIs, custom form fields) is supplied at
// call time. There is no provider detection.
package sts

import (
	"bytes"
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/entireio/auth-go/internal/oauthhttp"
	"github.com/entireio/auth-go/tokens"
)

// nowFunc is the package's clock. Override in tests.
var nowFunc = time.Now

// RFC 8693 grant_type and standard subject-token type URIs. Caller
// supplies RequestedTokenType (which is always implementation-specific
// outside of these RFC 8693 standard values).
const (
	GrantTypeTokenExchange = "urn:ietf:params:oauth:grant-type:token-exchange" //nolint:gosec // RFC 8693 grant_type URI, not a credential

	SubjectTokenTypeJWT         = "urn:ietf:params:oauth:token-type:jwt"          //nolint:gosec // RFC 8693 token-type URI, not a credential
	SubjectTokenTypeAccessToken = "urn:ietf:params:oauth:token-type:access_token" //nolint:gosec // RFC 8693 token-type URI, not a credential
)

// ExchangeRequest is the input to a token exchange.
//
// SubjectToken, SubjectTokenType, and RequestedTokenType are required.
// Audience, Resource, and Scope map to RFC 8693 §2.1 parameters and
// are sent only when non-empty. Extra carries implementation-specific
// form fields (e.g. server-defined parameters not in RFC 8693) that
// the caller's server expects; the standard fields above always win
// if Extra also sets them.
type ExchangeRequest struct {
	SubjectToken       string
	SubjectTokenType   string
	RequestedTokenType string

	Audience string
	Resource string
	Scope    string

	Extra url.Values
}

func (r ExchangeRequest) validate() error {
	switch {
	case r.SubjectToken == "":
		return errors.New("SubjectToken is required")
	case r.SubjectTokenType == "":
		return errors.New("SubjectTokenType is required")
	case r.RequestedTokenType == "":
		return errors.New("RequestedTokenType is required")
	}
	return nil
}

// DefaultRequestTimeout caps a single token-exchange round-trip. Set
// conservatively: even with a slow auth host plus TLS handshake, a
// healthy exchange completes in sub-seconds. The cap mainly defends
// against slow-loris responses dripping bytes within MaxResponseBytes
// — see Client.RequestTimeout for the per-Client override.
const DefaultRequestTimeout = 30 * time.Second

// Client exchanges subject tokens for tokens of a different type at an
// RFC 8693 token endpoint.
//
// All configuration is explicit; the package has no global state and
// no implicit URLs. Provide BaseURL and Path; the rest is RFC 8693.
type Client struct {
	// Transport supplies the http.RoundTripper used for all calls.
	// nil → http.DefaultTransport. The library builds its own
	// *http.Client around this transport so callers can't trivially
	// pass a *http.Client with TLS verification disabled. See the
	// deviceflow.Client.Transport doc for the security rationale.
	Transport http.RoundTripper

	BaseURL   string
	Path      string
	UserAgent string

	// RequestTimeout is the per-Exchange deadline applied via
	// context.WithTimeout on top of the caller's context. Zero falls
	// back to DefaultRequestTimeout. Negative disables the cap (useful
	// for tests that want to drive timing via the caller's ctx alone).
	RequestTimeout time.Duration

	// AllowInsecureHTTP permits http:// BaseURLs. Default (false) is
	// reject — token exchanges carry the subject token (a bearer) on
	// the wire and must be TLS-protected end to end. Production callers
	// MUST leave this false; only tests and local development that pin
	// the issuer to loopback should flip it.
	AllowInsecureHTTP bool
}

// Exchange performs one RFC 8693 token exchange.
//
// Returns a TokenSet with absolute ExpiresAt derived from the server's
// expires_in. Returns an error wrapping the response body when the
// server responds with a non-2xx status; callers can match on the
// returned error message for known OAuth error codes.
func (c *Client) Exchange(ctx context.Context, req ExchangeRequest) (*tokens.TokenSet, error) {
	if err := req.validate(); err != nil {
		return nil, fmt.Errorf("token exchange: %w", err)
	}

	form := buildForm(req)

	endpoint, err := resolveURL(c.BaseURL, c.Path, c.AllowInsecureHTTP)
	if err != nil {
		return nil, fmt.Errorf("token exchange: resolve URL: %w", err)
	}

	if timeout := c.requestTimeout(); timeout > 0 {
		var cancel context.CancelFunc
		ctx, cancel = context.WithTimeout(ctx, timeout)
		defer cancel()
	}

	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, strings.NewReader(form.Encode()))
	if err != nil {
		return nil, fmt.Errorf("token exchange: create request: %w", err)
	}
	httpReq.Header.Set("Accept", "application/json")
	httpReq.Header.Set("Content-Type", "application/x-www-form-urlencoded")
	if c.UserAgent != "" {
		httpReq.Header.Set("User-Agent", c.UserAgent)
	}

	resp, err := c.httpClient().Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("token exchange: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, readAPIError(resp)
	}

	var raw struct {
		AccessToken     string `json:"access_token"`
		IssuedTokenType string `json:"issued_token_type"`
		TokenType       string `json:"token_type"`
		ExpiresIn       int    `json:"expires_in"`
		RefreshToken    string `json:"refresh_token"`
		Scope           string `json:"scope"`
	}
	if err := oauthhttp.ReadAndDecodeJSON(resp.Body, &raw, false); err != nil {
		return nil, fmt.Errorf("token exchange: %w", err)
	}
	if raw.AccessToken == "" {
		return nil, errors.New("token exchange: response missing access_token")
	}

	// Exchanged tokens are short-lived per RFC 8693 §2.2.1's spirit
	// (the whole point of exchange is to issue narrowly-scoped,
	// short-lived bearers). A missing or non-positive expires_in is
	// either misconfiguration or a hostile AS — either way, we refuse
	// to cache a token of unknown lifetime and force a fresh exchange.
	if raw.ExpiresIn <= 0 {
		return nil, fmt.Errorf("token exchange: non-positive expires_in (%d)", raw.ExpiresIn)
	}

	return &tokens.TokenSet{
		AccessToken:  raw.AccessToken,
		RefreshToken: raw.RefreshToken,
		TokenType:    raw.TokenType,
		Scope:        raw.Scope,
		ExpiresAt:    nowFunc().Add(time.Duration(raw.ExpiresIn) * time.Second),
	}, nil
}

// buildForm renders an ExchangeRequest into the wire form, layering
// the standard RFC 8693 fields on top of req.Extra so caller-supplied
// duplicates of standard fields are overwritten by the typed values.
func buildForm(req ExchangeRequest) url.Values {
	form := url.Values{}
	for k, v := range req.Extra {
		form[k] = append(form[k], v...)
	}

	form.Set("grant_type", GrantTypeTokenExchange)
	form.Set("subject_token", req.SubjectToken)
	form.Set("subject_token_type", req.SubjectTokenType)
	form.Set("requested_token_type", req.RequestedTokenType)

	if req.Audience != "" {
		form.Set("audience", req.Audience)
	}
	if req.Resource != "" {
		form.Set("resource", req.Resource)
	}
	if req.Scope != "" {
		form.Set("scope", req.Scope)
	}
	return form
}

// httpClient builds the *http.Client used for one Exchange call. See
// oauthhttp.HTTPClient for the construction policy.
func (c *Client) httpClient() *http.Client {
	return oauthhttp.HTTPClient(c.Transport)
}

// requestTimeout resolves the effective per-request timeout: the
// configured RequestTimeout if positive, the package default if zero,
// or zero (no cap) if negative.
func (c *Client) requestTimeout() time.Duration {
	switch {
	case c.RequestTimeout < 0:
		return 0
	case c.RequestTimeout == 0:
		return DefaultRequestTimeout
	default:
		return c.RequestTimeout
	}
}

// ErrInsecureBaseURL is returned when Exchange is called against an
// http:// BaseURL without AllowInsecureHTTP set. Token exchange ships
// a subject_token (typically the user's core bearer) in the request
// body — over plain HTTP that's a credential in the clear. Re-exported
// from internal/oauthhttp so callers can errors.Is uniformly across
// deviceflow and sts.
var ErrInsecureBaseURL = oauthhttp.ErrInsecureBaseURL

// ErrAbsolutePath is returned when Path is an absolute or
// scheme-relative URL rather than a path relative to BaseURL. See
// oauthhttp.ErrAbsolutePath for the rationale; re-exported here so
// callers can errors.Is on either package's sentinel.
var ErrAbsolutePath = oauthhttp.ErrAbsolutePath

func resolveURL(baseURL, path string, allowInsecureHTTP bool) (string, error) {
	return oauthhttp.ResolveURL(baseURL, path, allowInsecureHTTP) //nolint:wrapcheck // pass through with sentinel-preserving semantics
}

type errorResponse struct {
	Error            string `json:"error"`
	ErrorDescription string `json:"error_description"`
}

// sanitizeDescription is a thin alias kept for in-package readability.
// The implementation lives in internal/oauthhttp.
func sanitizeDescription(s string) string { return oauthhttp.SanitizeDescription(s) }

func readAPIError(resp *http.Response) error {
	body, _ := io.ReadAll(io.LimitReader(resp.Body, oauthhttp.MaxResponseBytes)) //nolint:errcheck // best-effort body read for error message
	var apiErr errorResponse
	if err := json.Unmarshal(bytes.TrimSpace(body), &apiErr); err == nil && apiErr.Error != "" {
		if desc := sanitizeDescription(apiErr.ErrorDescription); desc != "" {
			return fmt.Errorf("token exchange: status %d: %s: %s", resp.StatusCode, apiErr.Error, desc)
		}
		return fmt.Errorf("token exchange: status %d: %s", resp.StatusCode, apiErr.Error)
	}
	text := strings.TrimSpace(string(body))
	if text != "" {
		return fmt.Errorf("token exchange: status %d: %s", resp.StatusCode, text)
	}
	return fmt.Errorf("token exchange: status %d", resp.StatusCode)
}

// Package tokenmanager orchestrates core-token storage and RFC 8693
// token exchanges for an OAuth 2.0 device-flow client.
//
// One Manager per CLI process. Construct it once from the embedding
// CLI's identity (Issuer, ClientID, STSPath, Store) and call
// TokenForResource / Token from data-API call sites.
//
// The package is provider-agnostic: every endpoint, identifier, and
// default value comes from Config. It has no env-var reads, no
// implicit URLs, and no embedded provider tables. Tests inject
// behaviour via SetExchangeForTest / SetNowForTest (see testseams.go)
// rather than via the public Config — keeping the STS call out of the
// caller-controllable surface.
package tokenmanager

import (
	"context"
	"errors"
	"fmt"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"sync/atomic"
	"time"

	"github.com/entireio/auth-go/sts"
	"github.com/entireio/auth-go/tokens"
	"github.com/entireio/auth-go/tokenstore"
)

// DefaultRequestedTokenType is the RFC 8693 §3 URI used when neither
// Config.RequestedTokenType nor TokenRequest.RequestedTokenType is set.
// :access_token is the canonical "give me an OAuth access token" URI;
// the wire format is the server's choice.
//
//nolint:gosec // RFC 8693 token-type URI, not a credential
const DefaultRequestedTokenType = "urn:ietf:params:oauth:token-type:access_token"

// exchangeSkew is the safety margin applied when deciding whether a
// cached exchanged token is still usable. Set conservatively because
// the worst case (re-exchange one extra time per command) is cheap.
const exchangeSkew = 30 * time.Second

// ErrNotLoggedIn is returned by Token / TokenForResource when no core
// token is present in the store. Callers can match on it to render a
// "run <login>" message.
var ErrNotLoggedIn = errors.New("not logged in")

// ErrNoSTSPath is returned when an exchange is needed but Config.STSPath
// is empty. Single-host deployments hit the same-host shortcut and never
// reach this; split-host deployments must configure STSPath.
var ErrNoSTSPath = errors.New("token exchange required but Config.STSPath is empty")

// Config configures a Manager.
type Config struct {
	// Issuer is the auth host base URL where the device-flow login
	// happened and STS exchanges are POSTed. Required. Doubles as the
	// Store profile key, so a user can be logged into multiple issuers
	// (e.g. regions / staging) without conflict.
	Issuer string

	// ClientID identifies the public client per RFC 6749 §2.3.1 / §3.2.1.
	// Sent on STS exchanges via the client_id form field. Required.
	ClientID string

	// STSPath is the path on Issuer where token-exchange requests are
	// POSTed. Optional: single-host deployments never trigger an
	// exchange (the same-host shortcut wins) so they can leave it
	// empty. When empty and an exchange is attempted, runExchange
	// returns ErrNoSTSPath rather than POSTing to a bogus URL.
	STSPath string

	// Store persists the core token. Required. Use any tokenstore.Store
	// implementation; a per-CLI service name keeps credentials isolated
	// from other CLIs sharing this library.
	Store tokenstore.Store

	// RequestedTokenType is the default RFC 8693 requested_token_type
	// URI. Empty → DefaultRequestedTokenType.
	RequestedTokenType string

	// Scope is the default scope sent on exchanges. Empty → omitted.
	Scope string

	// UserAgent for HTTP requests. Empty → none.
	UserAgent string

	// AllowInsecureHTTP permits exchanges against http:// issuers. Off
	// by default — STS calls ship the user's core token in the request
	// body and must be TLS-protected. Only flip this for local/dev
	// deployments pinned to loopback.
	AllowInsecureHTTP bool

	// Transport overrides the http.RoundTripper used for STS calls.
	// Useful for installing a debug logger or proxy. nil →
	// http.DefaultTransport. Replaces the previous HTTPClient field —
	// see sts.Client.Transport for the security rationale.
	Transport http.RoundTripper
}

func (c Config) validate() error {
	switch {
	case strings.TrimSpace(c.Issuer) == "":
		return errors.New("Config.Issuer is required")
	case strings.TrimSpace(c.ClientID) == "":
		return errors.New("Config.ClientID is required")
	case c.Store == nil:
		return errors.New("Config.Store is required")
	}
	return nil
}

// exchangeFunc / nowFuncType are named so we can hold them in
// atomic.Pointer values. Storing the override behind an
// atomic.Pointer rather than a plain field plus mu lets the hot read
// paths (runExchange, m.now) avoid taking the lock — they were
// previously racing with SetExchangeForTest / SetNowForTest.
type exchangeFunc func(ctx context.Context, req sts.ExchangeRequest) (*tokens.TokenSet, error)
type nowFuncType func() time.Time

// Manager orchestrates core-token storage and STS exchanges. Safe for
// concurrent use.
type Manager struct {
	cfg Config

	mu    sync.Mutex
	cache map[cacheKey]cachedToken

	// Test seams. Set only via SetExchangeForTest / SetNowForTest,
	// both of which require a testing.TB to discourage production
	// callers from synthesising a fake TB to bypass STS. Held behind
	// atomic.Pointer so hot-path reads (runExchange, now) don't race
	// against test setup/teardown.
	exchangeOverride atomic.Pointer[exchangeFunc]
	nowOverride      atomic.Pointer[nowFuncType]
}

// now returns the manager's effective clock. Tests can replace it via
// SetNowForTest; production callers always get time.Now.
func (m *Manager) now() time.Time {
	if p := m.nowOverride.Load(); p != nil {
		return (*p)()
	}
	return time.Now()
}

// New builds a Manager from cfg. Returns an error when required
// fields are missing or Issuer is not an absolute URL.
//
// Issuer is normalized via RFC 3986 §6.2.2 (lowercase scheme/host,
// default-port stripped, no trailing slash) before being used as the
// Store profile key and as the same-host shortcut comparison. Without
// this, two Managers configured with cosmetically-different issuers
// (`https://auth.example.com/` vs `https://auth.example.com`) would
// write to different keyring entries but compare equal for the
// shortcut — one Manager handing out the other's tokens.
func New(cfg Config) (*Manager, error) {
	if err := cfg.validate(); err != nil {
		return nil, err
	}
	parsed, err := url.Parse(cfg.Issuer)
	if err != nil || parsed.Scheme == "" || parsed.Host == "" {
		return nil, fmt.Errorf("Config.Issuer must be an absolute URL with scheme and host, got %q", cfg.Issuer)
	}
	cfg.Issuer = normalizeOriginURL(cfg.Issuer)
	if cfg.RequestedTokenType == "" {
		cfg.RequestedTokenType = DefaultRequestedTokenType
	}
	return &Manager{cfg: cfg, cache: map[cacheKey]cachedToken{}}, nil
}

// Issuer returns the configured issuer URL.
func (m *Manager) Issuer() string { return m.cfg.Issuer }

// SaveCoreToken persists the device-flow access token under the
// configured Issuer.
//
// On successful save the in-memory exchange cache is cleared so a
// re-login under a different identity can't return the previous user's
// exchanged tokens. The cacheKey already binds entries to CoreToken so
// this is defence-in-depth against a future refactor that drops the
// core token from the cache key — see TestSaveCoreToken_ClearsExchangeCache.
func (m *Manager) SaveCoreToken(accessToken string) error {
	if err := m.cfg.Store.SaveTokens(m.cfg.Issuer, tokens.TokenSet{AccessToken: accessToken}); err != nil {
		return fmt.Errorf("save core token: %w", err)
	}
	m.mu.Lock()
	m.cache = map[cacheKey]cachedToken{}
	m.mu.Unlock()
	return nil
}

// LookupCoreToken returns the stored core token, or "" if none is
// stored. A nil-return-no-error mirrors how callers expect
// "not-logged-in" to look.
func (m *Manager) LookupCoreToken() (string, error) {
	t, err := m.cfg.Store.LoadTokens(m.cfg.Issuer)
	if errors.Is(err, tokenstore.ErrNotFound) {
		return "", nil
	}
	if err != nil {
		return "", fmt.Errorf("load core token: %w", err)
	}
	return t.AccessToken, nil
}

// DeleteCoreToken removes the stored core token and any cached
// exchanges derived from it.
//
// Order matters: the keyring delete runs first, then the in-memory
// cache is cleared. If the keyring delete fails the cache is left
// alone — clearing it pre-emptively would create a window where the
// CLI thinks it's logged out (no cache entries) but the keyring
// still hands out the core token to the next process.
func (m *Manager) DeleteCoreToken() error {
	if err := m.cfg.Store.DeleteTokens(m.cfg.Issuer); err != nil {
		return fmt.Errorf("delete core token: %w", err)
	}
	m.mu.Lock()
	m.cache = map[cacheKey]cachedToken{}
	m.mu.Unlock()
	return nil
}

// TokenRequest customises one Token call. Empty fields fall back to
// Config defaults.
type TokenRequest struct {
	// Resource is the origin where the bearer will be presented.
	// Required. Used for the same-host shortcut, the JWT-aud shortcut,
	// and as part of the cache key.
	Resource string

	// Audience is the wire-level RFC 8693 audience parameter. Empty →
	// omitted (the AS picks). Independent of Resource — most callers
	// leave Audience empty.
	Audience string

	// RequestedTokenType overrides Config.RequestedTokenType for this
	// call. Empty → Config default.
	RequestedTokenType string

	// Scope overrides Config.Scope for this call. Empty → Config default.
	Scope string
}

// TokenForResource is a convenience for Token using only Resource.
func (m *Manager) TokenForResource(ctx context.Context, resourceBaseURL string) (string, error) {
	return m.Token(ctx, TokenRequest{Resource: resourceBaseURL})
}

// Token resolves a bearer token for use against req.Resource,
// performing an RFC 8693 exchange when needed.
//
// Resolution rules:
//
//  1. No core token in the store → ErrNotLoggedIn.
//  2. m.Issuer() == req.Resource (and req.Audience is empty) → use
//     the core token directly. Single-host deployments hit this path.
//  3. Core token's `aud` claim already includes req.Resource → use
//     the core token directly. Multi-audience tokens skip exchange.
//  4. Otherwise → RFC 8693 token exchange.
//
// Successful exchanges are cached in-memory keyed by (core token,
// resource, audience, requested-token-type, scope) until expiry.
func (m *Manager) Token(ctx context.Context, req TokenRequest) (string, error) {
	if strings.TrimSpace(req.Resource) == "" {
		return "", errors.New("TokenRequest.Resource is required")
	}

	core, err := m.LookupCoreToken()
	if err != nil {
		return "", err
	}
	if core == "" {
		return "", ErrNotLoggedIn
	}
	// Preflight expiry: a long-stored core token would otherwise hit the
	// resource (or STS) and surface as a confusing "invalid_grant" /
	// "401". Parse-failure is intentionally not treated as expired —
	// opaque (non-JWT) access tokens have no client-visible expiry, so
	// we let them flow and trust the server to reject if necessary.
	if coreTokenExpired(core, m.now()) {
		return "", ErrNotLoggedIn
	}

	normResource := normalizeOriginURL(req.Resource)

	// m.cfg.Issuer was normalized at New() time, so no re-normalize here.
	if req.Audience == "" && m.cfg.Issuer == normResource {
		return core, nil
	}
	if req.Audience == "" && coreTokenAudienceIncludes(core, normResource) {
		return core, nil
	}

	resolved := m.resolve(req)
	key := makeCacheKey(core, resolved, normResource)
	if hit, ok := m.cacheLookup(key); ok {
		return hit, nil
	}

	exchanged, err := m.runExchange(ctx, core, resolved)
	if err != nil {
		return "", err
	}
	m.cacheStore(key, exchanged)
	return exchanged.AccessToken, nil
}

// resolve fills empty TokenRequest fields with Config defaults.
func (m *Manager) resolve(req TokenRequest) TokenRequest {
	if req.RequestedTokenType == "" {
		req.RequestedTokenType = m.cfg.RequestedTokenType
	}
	if req.Scope == "" {
		req.Scope = m.cfg.Scope
	}
	return req
}

// coreTokenExpired reports whether the core token has an `exp` claim
// in the past at now. JWT parse failures (and tokens without an `exp`
// claim) are reported as not-expired so opaque access tokens flow
// through the rest of the resolution rules unchanged.
func coreTokenExpired(coreJWT string, now time.Time) bool {
	claims, err := tokens.ParseClaims(coreJWT)
	if err != nil {
		return false
	}
	if claims.ExpiresAt.IsZero() {
		return false
	}
	return !now.Before(claims.ExpiresAt)
}

// coreTokenAudienceIncludes reports whether the core JWT's `aud` claim
// covers target. target is expected to already be in normalised form
// (see normalizeOriginURL); aud entries are normalised here so a
// trailing-slash / case difference between the AS and the caller
// doesn't force a needless STS exchange.
func coreTokenAudienceIncludes(coreJWT, target string) bool {
	claims, err := tokens.ParseClaims(coreJWT)
	if err != nil {
		return false
	}
	for _, aud := range claims.Audience {
		if normalizeOriginURL(aud) == target {
			return true
		}
	}
	return false
}

// normalizeOriginURL canonicalises an origin URL for equality
// comparisons. RFC 3986 §6.2.2.1 makes scheme and host case-insensitive
// and §6.2.3 makes the empty path equivalent to "/" — we collapse to
// no-trailing-slash. Default ports (80/http, 443/https) are stripped.
//
// On parse failure (or when the input lacks a scheme or host — common
// for non-URL audiences) the input is returned unchanged so callers
// fall back to byte-exact comparison.
func normalizeOriginURL(raw string) string {
	u, err := url.Parse(raw)
	if err != nil || u.Scheme == "" || u.Host == "" {
		return raw
	}
	u.Scheme = strings.ToLower(u.Scheme)

	hostname := strings.ToLower(u.Hostname())
	port := u.Port()
	dropPort := (u.Scheme == "http" && port == "80") ||
		(u.Scheme == "https" && port == "443") ||
		port == ""

	switch {
	case dropPort && strings.Contains(hostname, ":"): // IPv6 without port
		u.Host = "[" + hostname + "]"
	case dropPort:
		u.Host = hostname
	case strings.Contains(hostname, ":"): // IPv6 with non-default port
		u.Host = "[" + hostname + "]:" + port
	default:
		u.Host = hostname + ":" + port
	}

	u.Path = strings.TrimRight(u.Path, "/")
	return u.String()
}

// maxCachedTokenLifetime bounds entries with an unknown wire-side
// expiry. Today this can't happen on the exchange path (sts.Exchange
// rejects non-positive expires_in), but it would still apply if a
// future code path stored a TokenSet without ExpiresAt — capping at 1h
// prevents an indefinitely-cached stale token in that case.
const maxCachedTokenLifetime = time.Hour

// cachedToken is one entry in the per-process exchange cache.
type cachedToken struct {
	accessToken string
	expiresAt   time.Time
	cachedAt    time.Time
}

func (c cachedToken) usable(now time.Time) bool {
	if c.accessToken == "" {
		return false
	}
	if c.expiresAt.IsZero() {
		return now.Sub(c.cachedAt) < maxCachedTokenLifetime
	}
	return now.Add(exchangeSkew).Before(c.expiresAt)
}

// cacheKey is a structurally-keyed exchange-cache key. Using a struct
// rather than a delimiter-joined string sidesteps any chance of two
// distinct (core token, resource, audience, requested-token-type,
// scope) tuples hashing to the same map slot via embedded delimiters
// in any field.
type cacheKey struct {
	CoreToken          string
	Resource           string
	Audience           string
	RequestedTokenType string
	Scope              string
}

// makeCacheKey builds a cacheKey from the (resolved) request. Includes
// every wire-affecting field so different combinations don't shadow
// each other. normalizedResource is the caller-supplied Resource after
// passing through normalizeOriginURL, so https://api.example.com and
// https://api.example.com/ share a single cache entry.
func makeCacheKey(coreToken string, req TokenRequest, normalizedResource string) cacheKey {
	return cacheKey{
		CoreToken:          coreToken,
		Resource:           normalizedResource,
		Audience:           req.Audience,
		RequestedTokenType: req.RequestedTokenType,
		Scope:              req.Scope,
	}
}

func (m *Manager) cacheLookup(key cacheKey) (string, bool) {
	m.mu.Lock()
	defer m.mu.Unlock()
	entry, ok := m.cache[key]
	if !ok {
		return "", false
	}
	if !entry.usable(m.now()) {
		delete(m.cache, key)
		return "", false
	}
	return entry.accessToken, true
}

func (m *Manager) cacheStore(key cacheKey, t *tokens.TokenSet) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.cache[key] = cachedToken{
		accessToken: t.AccessToken,
		expiresAt:   t.ExpiresAt,
		cachedAt:    m.now(),
	}
}

// runExchange dispatches to either Config.Exchange (test override) or
// a freshly built sts.Client pointing at m.cfg.Issuer + m.cfg.STSPath.
func (m *Manager) runExchange(ctx context.Context, coreToken string, req TokenRequest) (*tokens.TokenSet, error) {
	stsReq := sts.ExchangeRequest{
		SubjectToken:       coreToken,
		SubjectTokenType:   sts.SubjectTokenTypeJWT,
		RequestedTokenType: req.RequestedTokenType,
		Audience:           req.Audience,
		Resource:           req.Resource,
		Scope:              req.Scope,
		// Public-client identification per RFC 6749 §2.3.1 / §3.2.1.
		// Carried via Extra because the sts package is provider-agnostic.
		Extra: url.Values{"client_id": {m.cfg.ClientID}},
	}

	if p := m.exchangeOverride.Load(); p != nil {
		return (*p)(ctx, stsReq)
	}

	if strings.TrimSpace(m.cfg.STSPath) == "" {
		return nil, ErrNoSTSPath
	}

	stsClient := &sts.Client{
		Transport:         m.cfg.Transport,
		BaseURL:           m.cfg.Issuer,
		Path:              m.cfg.STSPath,
		UserAgent:         m.cfg.UserAgent,
		AllowInsecureHTTP: m.cfg.AllowInsecureHTTP,
	}
	return stsClient.Exchange(ctx, stsReq) //nolint:wrapcheck // sts.Exchange already prefixes "token exchange:"
}

// Package tokens defines the post-protocol token shape and helpers for
// reading unverified claims out of JWT access tokens.
//
// The wire-shape responses from RFC 8628 / RFC 8693 endpoints are
// translated into a single TokenSet with absolute expiry. Clients that
// only ever see access tokens as opaque bearer strings need not import
// this package directly.
package tokens

import (
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"strings"
	"time"
)

// TokenSet is an OAuth token bundle returned from a device-flow or
// token-exchange endpoint, normalised to absolute expiry.
//
// RefreshToken is empty when the issuer didn't return one. ExpiresAt is
// zero for tokens that don't carry a wire-side expires_in.
type TokenSet struct {
	AccessToken  string
	RefreshToken string
	TokenType    string
	ExpiresAt    time.Time
	Scope        string
}

// HasRefresh reports whether the set carries a refresh token.
func (t TokenSet) HasRefresh() bool { return t.RefreshToken != "" }

// Expired reports whether the access token's advertised lifetime has
// elapsed at now. Returns false for tokens with a zero ExpiresAt.
func (t TokenSet) Expired(now time.Time) bool {
	if t.ExpiresAt.IsZero() {
		return false
	}
	return !now.Before(t.ExpiresAt)
}

// ShouldRefresh reports whether the access token is within skew of
// expiring (or has already expired). Tokens without an advertised
// expiry never need refreshing.
func (t TokenSet) ShouldRefresh(now time.Time, skew time.Duration) bool {
	if t.ExpiresAt.IsZero() {
		return false
	}
	return !now.Add(skew).Before(t.ExpiresAt)
}

// Claims holds the fields parsed from a JWT access token's payload.
//
// Signature verification is the issuing server's responsibility; this
// package never validates signatures. Clients read claims for routing
// (which issuer, which audience) and UX (display the principal handle).
type Claims struct {
	Issuer    string
	Subject   string
	Audience  []string
	Handle    string
	ExpiresAt time.Time
	IssuedAt  time.Time
	NotBefore time.Time
}

// ErrMalformedJWT is returned by ParseClaims when the input is not a
// well-formed JWT (three base64url-encoded segments separated by dots).
var ErrMalformedJWT = errors.New("malformed JWT")

// ErrUnsignedJWT is returned by ParseClaims when the JWT header
// declares `alg: none`. The unsigned-JWT shape was deprecated by
// RFC 7518 §3.6 and is a known attack vector (an attacker can craft
// arbitrary claims that pass shape checks). Defense in depth: even
// though this package never trusts claims for authorization
// decisions, we refuse to parse them so a future caller can't be
// tricked into routing on attacker-controlled values.
var ErrUnsignedJWT = errors.New("refusing to parse unsigned JWT (alg:none)")

// ParseClaims decodes the payload segment of jwt without verifying the
// signature. Audience is normalised to a slice even when the wire form
// is a single string.
//
// Rejects JWTs whose header declares `alg: none` — see ErrUnsignedJWT
// for the rationale. The signature payload itself is still not
// verified; that remains the issuing server's responsibility.
func ParseClaims(jwt string) (*Claims, error) {
	parts := strings.Split(jwt, ".")
	if len(parts) != 3 {
		return nil, fmt.Errorf("%w: expected 3 segments, got %d", ErrMalformedJWT, len(parts))
	}

	header, err := base64.RawURLEncoding.DecodeString(parts[0])
	if err != nil {
		return nil, fmt.Errorf("decode JWT header: %w", err)
	}
	var hdr struct {
		Alg string `json:"alg"`
	}
	if err := json.Unmarshal(header, &hdr); err != nil {
		return nil, fmt.Errorf("decode JWT header: %w", err)
	}
	// JWS algorithm identifiers (RFC 7515 §4.1.1, IANA "JSON Web
	// Signature and Encryption Algorithms" registry) are ASCII
	// alphanumeric only — "HS256", "RS512", "EdDSA", "none", …
	//
	// Anything else is malformed. Rejecting non-alphanumeric runes
	// here closes a class of bypasses against the alg:none check:
	// `strings.TrimSpace` only handles unicode.IsSpace, missing
	// U+200B (zero-width space), U+FEFF (BOM), and other invisible
	// chars that a hostile AS could pad around "none" to slip past
	// a case-fold comparison.
	for _, r := range hdr.Alg {
		if (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9') {
			continue
		}
		return nil, fmt.Errorf("%w: alg contains non-alphanumeric character", ErrMalformedJWT)
	}
	// Case-insensitive because RFC 7515 §4.1.1 doesn't strictly
	// canonicalise case, and "None" / "NONE" have been observed in
	// the wild.
	if strings.EqualFold(hdr.Alg, "none") {
		return nil, ErrUnsignedJWT
	}

	payload, err := base64.RawURLEncoding.DecodeString(parts[1])
	if err != nil {
		return nil, fmt.Errorf("decode JWT payload: %w", err)
	}

	var raw struct {
		Iss    string          `json:"iss"`
		Sub    string          `json:"sub"`
		Aud    json.RawMessage `json:"aud"`
		Exp    int64           `json:"exp"`
		Iat    int64           `json:"iat"`
		Nbf    int64           `json:"nbf"`
		Handle string          `json:"handle"`
	}
	if err := json.Unmarshal(payload, &raw); err != nil {
		return nil, fmt.Errorf("decode JWT claims: %w", err)
	}

	c := &Claims{
		Issuer:  raw.Iss,
		Subject: raw.Sub,
		Handle:  raw.Handle,
	}

	if raw.Exp != 0 {
		c.ExpiresAt = time.Unix(raw.Exp, 0).UTC()
	}
	if raw.Iat != 0 {
		c.IssuedAt = time.Unix(raw.Iat, 0).UTC()
	}
	if raw.Nbf != 0 {
		c.NotBefore = time.Unix(raw.Nbf, 0).UTC()
	}

	c.Audience, err = decodeAudience(raw.Aud)
	if err != nil {
		return nil, err
	}

	return c, nil
}

// decodeAudience handles both string and string-array forms of the JWT
// `aud` claim.
func decodeAudience(raw json.RawMessage) ([]string, error) {
	if len(raw) == 0 {
		return nil, nil
	}

	var single string
	if err := json.Unmarshal(raw, &single); err == nil {
		if single == "" {
			return nil, nil
		}
		return []string{single}, nil
	}

	var multi []string
	if err := json.Unmarshal(raw, &multi); err == nil {
		return multi, nil
	}

	return nil, errors.New("decode JWT aud claim: not a string or array")
}

// Package tokenstore is the persistence interface for tokens, plus
// the Keyring reference implementation.
//
// Profile is whatever string the caller wants to key by — typically a
// base URL, a kubectl-style context name, or a principal handle.
package tokenstore

import (
	"errors"

	"github.com/entireio/auth-go/tokens"
)

// ErrNotFound is returned when a profile has no stored tokens. Callers
// distinguish "not logged in" from genuine errors with errors.Is.
var ErrNotFound = errors.New("token not found")

// ErrMalformed is returned (wrapped) when a stored entry exists but
// can't be decoded into a TokenSet. Used by callers that want to treat
// a malformed entry as a legacy/upgrade path (e.g. pre-shim bare-string
// entries from older binaries) without confusing it with transport
// errors from the underlying keyring.
var ErrMalformed = errors.New("malformed token entry")

// Store persists token bundles keyed by an opaque profile string.
//
// Implementations must:
//   - Return ErrNotFound (not a zero value, no error) when LoadTokens
//     is called for an unknown profile.
//   - Treat DeleteTokens of a missing profile as a no-op.
//   - Not write empty access tokens; SaveTokens should reject them.
type Store interface {
	SaveTokens(profile string, t tokens.TokenSet) error
	LoadTokens(profile string) (tokens.TokenSet, error)
	DeleteTokens(profile string) error
}

package tokenstore

import (
	"encoding/json"
	"errors"
	"fmt"
	"strings"
	"time"

	"github.com/entireio/auth-go/tokens"
	"github.com/zalando/go-keyring"
)

// Keyring is a Store backed by the OS keyring.
//
// Each profile gets one entry under the configured Service name. The
// entry holds a JSON-encoded TokenSet so refresh tokens, expiry, and
// scope round-trip alongside the access token.
type Keyring struct {
	Service string
}

// NewKeyring returns a Keyring with the given service name. The service
// name namespaces entries in the OS keyring; pick something unique per
// CLI binary so two CLIs don't collide.
func NewKeyring(service string) *Keyring {
	return &Keyring{Service: service}
}

// SaveTokens marshals t to JSON and stores it under profile in the OS
// keyring. Empty access tokens are rejected.
func (k *Keyring) SaveTokens(profile string, t tokens.TokenSet) error {
	t.AccessToken = strings.TrimSpace(t.AccessToken)
	if t.AccessToken == "" {
		return errors.New("refusing to save TokenSet with empty access token")
	}

	encoded, err := encodeTokenSet(t)
	if err != nil {
		return err
	}

	if err := keyring.Set(k.Service, profile, encoded); err != nil {
		return fmt.Errorf("save tokens to keyring: %w", err)
	}
	return nil
}

// LoadTokens returns the TokenSet stored for profile. Returns
// ErrNotFound when the profile has nothing stored.
func (k *Keyring) LoadTokens(profile string) (tokens.TokenSet, error) {
	raw, err := keyring.Get(k.Service, profile)
	if errors.Is(err, keyring.ErrNotFound) {
		return tokens.TokenSet{}, ErrNotFound
	}
	if err != nil {
		return tokens.TokenSet{}, fmt.Errorf("load tokens from keyring: %w", err)
	}

	t, err := decodeTokenSet(raw)
	if err != nil {
		return tokens.TokenSet{}, err
	}
	return t, nil
}

// DeleteTokens removes the TokenSet for profile. A missing entry is a
// no-op.
func (k *Keyring) DeleteTokens(profile string) error {
	err := keyring.Delete(k.Service, profile)
	if errors.Is(err, keyring.ErrNotFound) {
		return nil
	}
	if err != nil {
		return fmt.Errorf("delete tokens from keyring: %w", err)
	}
	return nil
}

// keyringTokenSet is the on-keyring JSON shape. Time fields are
// serialised as RFC 3339 strings so the wire form survives keyring
// implementations that don't preserve byte-for-byte equality. The
// access_token is intentionally serialised so the OS keyring
// (encrypted at rest) holds the full TokenSet for round-tripping.
type keyringTokenSet struct {
	AccessToken  string `json:"access_token"`
	RefreshToken string `json:"refresh_token,omitempty"`
	TokenType    string `json:"token_type,omitempty"`
	ExpiresAt    string `json:"expires_at,omitempty"`
	Scope        string `json:"scope,omitempty"`
}

func encodeTokenSet(t tokens.TokenSet) (string, error) {
	wire := keyringTokenSet{
		AccessToken:  t.AccessToken,
		RefreshToken: t.RefreshToken,
		TokenType:    t.TokenType,
		Scope:        t.Scope,
	}
	if !t.ExpiresAt.IsZero() {
		wire.ExpiresAt = t.ExpiresAt.UTC().Format(time.RFC3339)
	}

	b, err := json.Marshal(wire) //nolint:gosec // intentional: serialise the access token for OS-keyring storage (encrypted at rest)
	if err != nil {
		return "", fmt.Errorf("marshal TokenSet: %w", err)
	}
	return string(b), nil
}

func decodeTokenSet(raw string) (tokens.TokenSet, error) {
	var wire keyringTokenSet
	if err := json.Unmarshal([]byte(raw), &wire); err != nil {
		return tokens.TokenSet{}, fmt.Errorf("%w: unmarshal TokenSet: %w", ErrMalformed, err)
	}

	// json.Unmarshal happily decodes any well-formed JSON object to a
	// zero keyringTokenSet — for example {} or an unrelated CLI's blob
	// that happens to be keyed against the same (service, profile). We
	// surface that as ErrMalformed so the embedding shim can route to
	// its legacy/upgrade path rather than returning a TokenSet with an
	// empty AccessToken (which the caller can't distinguish from a
	// successful load of a freshly-cleared entry).
	if strings.TrimSpace(wire.AccessToken) == "" {
		return tokens.TokenSet{}, fmt.Errorf("%w: stored entry has no access_token", ErrMalformed)
	}

	t := tokens.TokenSet{
		AccessToken:  wire.AccessToken,
		RefreshToken: wire.RefreshToken,
		TokenType:    wire.TokenType,
		Scope:        wire.Scope,
	}
	if wire.ExpiresAt != "" {
		exp, err := time.Parse(time.RFC3339, wire.ExpiresAt)
		if err != nil {
			return tokens.TokenSet{}, fmt.Errorf("%w: parse expires_at: %w", ErrMalformed, err)
		}
		t.ExpiresAt = exp.UTC()
	}
	return t, nil
}

package oauthhttp

import (
	"errors"
	"fmt"
	"net/url"
)

// ErrInsecureBaseURL is returned by ResolveURL when handed an
// http:// BaseURL without allowInsecureHTTP set. OAuth flows ship
// the user's bearer (subject_token, refresh_token, access_token) on
// the wire — over plain HTTP that's a credential in the clear.
// Public packages re-export this sentinel so callers can errors.Is
// on the familiar deviceflow.ErrInsecureBaseURL / sts.ErrInsecureBaseURL.
var ErrInsecureBaseURL = errors.New("refusing to perform OAuth request over plain HTTP (set AllowInsecureHTTP only for local dev / test)")

// ErrAbsolutePath is returned by ResolveURL when the path is an
// absolute or scheme-relative URL rather than a path relative to
// BaseURL. Go's url.ResolveReference replaces BaseURL's host when
// handed an absolute reference, so accepting an absolute path
// would let any caller who can influence the configuration (env
// var, config file, server-discovery doc) redirect the request to
// an attacker — and capture whatever bearer the request carries.
var ErrAbsolutePath = errors.New("path must be a relative URL, not absolute")

// ResolveURL joins baseURL and path the way the OAuth flows want:
//
//   - baseURL must parse, must have scheme http or https.
//   - If scheme is http, allowInsecureHTTP must be true (otherwise
//     ErrInsecureBaseURL).
//   - path must parse and must be relative — neither absolute
//     (e.g. "https://other") nor scheme-relative (e.g.
//     "//other/path") references are accepted (otherwise
//     ErrAbsolutePath). Without this guard, a caller controlling
//     path could redirect the user's bearer to an attacker.
func ResolveURL(baseURL, path string, allowInsecureHTTP bool) (string, error) {
	base, err := url.Parse(baseURL)
	if err != nil {
		return "", fmt.Errorf("parse base URL: %w", err)
	}
	switch base.Scheme {
	case "https":
		// fine
	case "http":
		if !allowInsecureHTTP {
			return "", ErrInsecureBaseURL
		}
	default:
		return "", fmt.Errorf("unsupported base URL scheme %q (must be http or https)", base.Scheme)
	}
	rel, err := url.Parse(path)
	if err != nil {
		return "", fmt.Errorf("parse path: %w", err)
	}
	// Reject both scheme-relative (e.g. "//host/path") and absolute
	// references — both override BaseURL's host via url.ResolveReference.
	if rel.IsAbs() || rel.Host != "" {
		return "", fmt.Errorf("%w: got %q", ErrAbsolutePath, path)
	}
	return base.ResolveReference(rel).String(), nil
}

// Package oauthhttp holds shared HTTP-response helpers used by the
// auth subpackages. Internal: only auth/* may import.
package oauthhttp

import (
	"bytes"
	"encoding/json"
	"errors"
	"fmt"
	"io"
)

// MaxResponseBytes caps how much of an OAuth response body we read.
// Both device-flow and token-exchange endpoints return small JSON
// documents; larger bodies indicate a misconfigured proxy or an
// attempt to exhaust client memory.
const MaxResponseBytes = 1 << 20

// ErrNonJSONResponse is returned by ReadAndDecodeJSON when a 200 OK
// from the authorization server's body looks like HTML rather than
// JSON — typically a captive portal, corporate proxy, or VPN firewall
// (Cloudflare WARP, etc.) intercepting the request and returning an
// error page.
//
// Callers can match with errors.Is and surface a UX message; the
// default Error() string is already user-readable.
var ErrNonJSONResponse = errors.New(
	"could not reach authentication server: server returned non-JSON " +
		"response (check VPN, proxy, or firewall — e.g. Cloudflare WARP)",
)

// ReadAndDecodeJSON reads up to MaxResponseBytes from r and decodes
// the body as JSON into dest. When strict is true, unknown fields are
// rejected.
//
// Returns ErrNonJSONResponse when the body is HTML — the captive-
// portal / proxy-interceptor case. Other read or decode failures are
// wrapped with context.
func ReadAndDecodeJSON(r io.Reader, dest any, strict bool) error {
	body, err := io.ReadAll(io.LimitReader(r, MaxResponseBytes))
	if err != nil {
		return fmt.Errorf("read JSON response: %w", err)
	}
	if looksLikeHTML(body) {
		return ErrNonJSONResponse
	}

	dec := json.NewDecoder(bytes.NewReader(body))
	if strict {
		dec.DisallowUnknownFields()
	}
	if err := dec.Decode(dest); err != nil {
		return fmt.Errorf("decode JSON response: %w", err)
	}
	return nil
}

// looksLikeHTML reports whether body's first non-whitespace byte is
// '<'. That covers HTML, XHTML, XML, and most captive-portal error
// pages without trying to fully sniff the document.
func looksLikeHTML(body []byte) bool {
	trimmed := bytes.TrimSpace(body)
	return len(trimmed) > 0 && trimmed[0] == '<'
}

package oauthhttp

import "net/http"

// HTTPClient builds the *http.Client used for one OAuth request.
//
// Always returns a freshly-allocated *http.Client so this library's
// requests are isolated from mutations to http.DefaultClient (any
// process-wide Timeout or Transport swap by another package would
// otherwise be inherited). The underlying Transport is the
// caller-supplied transport when non-nil, or http.DefaultTransport
// otherwise — sharing a Transport is intentional (it owns the
// connection pool) and safe (Transport.RoundTrip is concurrent-safe).
//
// Per-request timeouts must be driven by ctx.WithTimeout in the
// caller, not by *http.Client.Timeout — the body-read happens after
// client.Do returns, and Client.Timeout would cancel that read.
func HTTPClient(transport http.RoundTripper) *http.Client {
	if transport == nil {
		transport = http.DefaultTransport
	}
	return &http.Client{Transport: transport}
}

