)

// RFC 8693 well-known URN values used by the token-exchange endpoint.
// Hard-coded as constants rather than imported from a library — the
// endpoint accepts exactly these values today, and stricter matching
// is preferable to permissive normalization for an auth surface.
//
// The three issued-token URNs are entire-specific: RFC 8693 reserves
// `urn:ietf:params:oauth:token-type:` for IETF-registered token types,
// so we publish our own under `urn:entire:token-type:`. Callers
// distinguish a repo-scoped, ops-scoped, or SA-session exchange via
// `requested_token_type`; the field is required, so future shapes can
// be added without silently shadowing today's behaviour.
const (
	stsGrantTypeTokenExchange     = "urn:ietf:params:oauth:grant-type:token-exchange" //nolint:gosec // URN, not a credential
	stsTokenTypeJWT               = "urn:ietf:params:oauth:token-type:jwt"            //nolint:gosec // URN, not a credential
	stsTokenTypeAccessToken       = "urn:ietf:params:oauth:token-type:access_token"   //nolint:gosec // URN, not a credential
	stsTokenTypeSASession         = "urn:entire:token-type:sa-session"                //nolint:gosec // URN, not a credential
	stsTokenTypeRepoAccess        = "urn:entire:token-type:repo-access"
	stsTokenTypeOpsAccess         = "urn:entire:token-type:ops-access"
	stsTokenTypeGitHubAccessToken = "urn:entire:token-type:github-access-token"
)

// validSTSSubjectTokenTypes are the RFC 8693 subject_token_type URIs we
// accept on /api/authz/sts/token. The bearer is always a JWT issued by
// entire-core; "jwt" describes its structure, "access_token" describes
// its role. RFC 8693 §2.1 lists both as valid for a JWT bearer, so we
// accept both — the entire-web RP and any RFC-conforming generic OAuth
// client tend to send `access_token` for OIDC-style bearers, while
// in-tree CLIs historically send `jwt`.
var validSTSSubjectTokenTypes = map[string]bool{
	stsTokenTypeJWT:         true,
	stsTokenTypeAccessToken: true,
}

// stsMaxFormBytes caps the size of an inbound /api/authz/sts/token
// form body. RFC 8693 form fields are at most JWT-sized; 64 KiB is
// well above any legitimate request and bounds the memory exposure
// from a malicious client that could otherwise stream an unbounded
// body into ParseForm.
const stsMaxFormBytes = 64 * 1024

// oidcVerifierCacheTTL is how long a per-provider JWKS cache survives
// before re-fetching. Five minutes mirrors entire-core's own JWKS
// verifier cache and is well within the rotation window of every IdP
// we federate with (GitHub rotates ~hourly).
const oidcVerifierCacheTTL = 5 * time.Minute

// handleSTSTokenExchange is POST /api/authz/sts/token implementing
// RFC 8693. Dispatches on `requested_token_type`:
//
//   - `urn:entire:token-type:sa-session` → service-account session
//     token. Subject is either an entire-core login JWT (operator
//     path: org#manage gate), an external OIDC token (federated
//     path: provider binding gate), or an internal mTLS workload mapped
//     to a fixed service account.
//   - `urn:entire:token-type:repo-access` → repo-scoped JWT for git
//     traffic. Subject is a login JWT; gate is repo#pull / repo#push
//     in SpiceDB. Resource carries the repo path; scope picks action.
//   - `urn:entire:token-type:ops-access` → ops JWT carrying platform-
//     admin authority. Subject is a login JWT or sa_session; gate is
//     platform#admin.
//   - `urn:entire:token-type:github-access-token` → fresh GitHub
//     access token for mirror-push attribution. Subject is a login
//     JWT; the github-tokens store refreshes against GitHub if the
//     stored token is near expiry.
//
// All branches return the same RFC 8693 response envelope so callers
// don't fork on token shape.
func (s *Server) handleSTSTokenExchange(w http.ResponseWriter, r *http.Request) {
	r.Body = http.MaxBytesReader(w, r.Body, stsMaxFormBytes)
	if err := r.ParseForm(); err != nil {
		http.Error(w, `{"error":"invalid form body"}`, http.StatusBadRequest)
		return
	}

	if got := r.PostForm.Get("grant_type"); got != stsGrantTypeTokenExchange {
		http.Error(w, `{"error":"unsupported_grant_type"}`, http.StatusBadRequest)
		return
	}

	requestedTokenType := r.PostForm.Get("requested_token_type")
	subjectToken := r.PostForm.Get("subject_token")
	if subjectToken == "" {
		if requestedTokenType == stsTokenTypeSASession {
			if _, ok := servicetoken.CallerFromContext(r.Context()); ok {
				s.handleInternalWorkloadServiceAccountExchange(w, r)
				return
			}
		}
		http.Error(w, `{"error":"subject_token is required"}`, http.StatusBadRequest)
		return
	}
	if got := r.PostForm.Get("subject_token_type"); !validSTSSubjectTokenTypes[got] {
		http.Error(w, `{"error":"unsupported subject_token_type"}`, http.StatusBadRequest)
		return
	}

	switch requestedTokenType {
	case stsTokenTypeSASession:
		s.handleServiceAccountExchange(w, r, subjectToken)
	case stsTokenTypeRepoAccess:
		s.handleRepoTokenExchange(w, r, subjectToken)
	case stsTokenTypeOpsAccess:
		s.handleOpsTokenExchange(w, r, subjectToken)
	case stsTokenTypeGitHubAccessToken:
		s.handleGitHubAccessTokenExchange(w, r, subjectToken)
	case stsTokenTypeJWT, stsTokenTypeAccessToken:
		// RFC 8693 standard URIs map to the user-facing API-access token
		// — the customer CLI and entire-web RP both ask for one of these

